mapper.update:
update jst_contest
set audit_status = #{targetAuditStatus},
    update_by = #{updateBy},
    update_time = #{updateTime}

        , remark = #{auditRemark}

where contest_id = #{contestId}
  and audit_status = #{expectedAuditStatus}
  and del_flag = '0'

update jst_contest
set audit_status = #{targetAuditStatus},
    status = #{targetBizStatus},
    update_by = #{updateBy},
    update_time = #{updateTime}
where contest_id = #{contestId}
  and audit_status = #{expectedAuditStatus}
  and status = #{expectedBizStatus}
  and del_flag = '0'

update jst_contest
set del_flag = '2',
    update_by = #{updateBy},
    update_time = #{updateTime}
where contest_id = #{contestId}
  and audit_status = #{expectedAuditStatus}
  and del_flag = '0'

mapper.select:
select c.contest_id AS contestId, c.contest_name AS contestName, c.category AS category, c.group_levels AS groupLevels, c.cover_image AS coverImage, c.price AS price, c.enroll_start_time AS enrollStartTime, c.enroll_end_time AS enrollEndTime, c.event_start_time AS eventStartTime, c.event_end_time AS eventEndTime, ( select count(1) from jst_enroll_record er where er.contest_id = c.contest_id and er.del_flag = '0' ) AS enrollCount, c.audit_status AS auditStatus, c.remark AS auditRemark, c.status AS status, c.partner_id AS partnerId, p.partner_name AS partnerName, c.recommend_tags AS recommendTags from jst_contest c left join jst_event_partner p on p.partner_id = c.partner_id and p.del_flag = '0'
c.del_flag = '0'
and c.contest_name like concat('%', #{query.contestName}, '%')
and c.category = #{query.category}
and c.audit_status = #{query.auditStatus}
and c.status = #{query.status}
and c.partner_id = #{query.partnerId}
and c.create_time >= #{query.beginCreateTime}
and c.create_time <= #{query.endCreateTime}
${query.params.dataScope}
order by c.create_time desc, c.contest_id desc

select c.contest_id AS contestId, c.contest_name AS contestName, c.category AS category, c.group_levels AS groupLevels, c.cover_image AS coverImage, c.price AS price, c.enroll_start_time AS enrollStartTime, c.enroll_end_time AS enrollEndTime, c.event_start_time AS eventStartTime, c.event_end_time AS eventEndTime, c.audit_status AS auditStatus, c.remark AS auditRemark, c.status AS status, c.partner_id AS partnerId, p.partner_name AS partnerName, c.recommend_tags AS recommendTags from jst_contest c left join jst_event_partner p on p.partner_id = c.partner_id and p.del_flag = '0' where c.del_flag = '0' and c.audit_status = 'online' and c.contest_id != #{contestId}
and c.category = #{category}
order by c.enroll_start_time desc, c.contest_id desc limit #{limit}

select c.course_id AS courseId, c.course_name AS courseName, c.cover_image AS coverImage, c.price AS price, ifnull(l.learner_count, 0) AS learnerCount from jst_course c left join ( select course_id, count(1) AS learner_count from jst_course_learn_record where del_flag = '0' group by course_id ) l on l.course_id = c.course_id where c.del_flag = '0' and c.audit_status = 'approved' and c.status = 'on' and (
( c.course_name like concat('%', #{tag}, '%') or c.description like concat('%', #{tag}, '%') or c.remark like concat('%', #{tag}, '%') )
) order by learnerCount desc, c.update_time desc, c.course_id desc limit #{limit}
